func (s *Service) GetWorker(id int) (*Worker, error) {
        var w Worker
        err := s.db.QueryRow(
                "SELECT id, name, status, registered_at FROM workers WHERE id=?", id,
        ).Scan(&w.ID, &w.Name, &w.Status, &w.RegisteredAt)
