func (s *Service) ListWorkers() ([]Worker, error) {
        rows, err := s.db.Query("SELECT id, name, status, registered_at FROM workers ORDER BY id")
        if err != nil {
                return nil, err
        }
        defer rows.Close()

        var workers []Worker
        for rows.Next() {
                var w Worker
                if err := rows.Scan(&w.ID, &w.Name, &w.Status, &w.RegisteredAt); err != nil {
                        return nil, err
                }
                workers = append(workers, w)
        }
        return workers, rows.Err()
}

func (s *Service) GetStats() (*QueueStats, error) {
        stats := &QueueStats{}
        rows, err := s.db.Query("SELECT status, COUNT(*) FROM jobs GROUP BY status")
        if err != nil {
                return nil, err
        }
        defer rows.Close()
        for rows.Next() {
                var status string
                var count int
                if err := rows.Scan(&status, &count); err != nil {
                        return nil, err
                }
                switch status {
                case "pending":
                        stats.Pending = count
                case "running":
                        stats.Running = count
                case "completed":
                        stats.Completed = count
                case "failed":
                        stats.Failed = count
                case "cancelled":
                        stats.Cancelled = count
                }
        }
        return stats, rows.Err()
}
