type WorkerPool struct {
        mu         sync.Mutex
        maxWorkers int
        active     int
        db         *sql.DB
        quit       chan struct{}
}

func NewWorkerPool(max int, db *sql.DB) *WorkerPool {
        return &WorkerPool{
                maxWorkers: max,
                db:         db,
                quit:       make(chan struct{}),
        }
}

func (p *WorkerPool) SetMax(n int) {
        p.mu.Lock()
        defer p.mu.Unlock()
        log.Printf("pool: max_workers %d -> %d", p.maxWorkers, n)
        p.maxWorkers = n
}

func (p *WorkerPool) Start() {
        go p.poll()
}

func (p *WorkerPool) Stop() {
        close(p.quit)
}

func (p *WorkerPool) poll() {
        ticker := time.NewTicker(500 * time.Millisecond)
        defer ticker.Stop()
        for {
                select {
                case <-p.quit:
                        return
                case <-ticker.C:
                        p.mu.Lock()
                        slots := p.maxWorkers - p.active
                        p.mu.Unlock()

                        for i := 0; i < slots; i++ {
                                job, err := p.claimNextPending()
                                if err != nil {
                                        log.Printf("poll claim error: %v", err)
                                        break
                                }
                                if job == nil {
                                        break
                                }
                                p.mu.Lock()
                                p.active++
                                p.mu.Unlock()

                                go func(jobID int) {
                                        defer func() {
                                                p.mu.Lock()
                                                p.active--
                                                p.mu.Unlock()
                                        }()
                                        p.process(jobID)
                                }(job.id)
                        }
                }
        }
}

