                return
        }
        if req.Type == "" {
                writeError(w, http.StatusBadRequest, "type is required")
                return
        }
        job, err := h.svc.CreateJob(req)
        if err != nil {
                writeError(w, http.StatusInternalServerError, err.Error())
                return
        }
        writeJSON(w, http.StatusOK, job)
}

