        ); err != nil {
                return nil, err
        }
        return s.GetJob(id)
}

func (s *Service) CompleteJob(id int) (*Job, error) {
        job, err := s.GetJob(id)
        if err != nil {
                return nil, err
        }
        if job.Status != "running" {
                return nil, fmt.Errorf("%w: job must be running to complete, got %q", ErrConflict, job.Status)
        }
        if _, err := s.db.Exec(
